import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

function VideoPlayerPage() {
  const { id } = useParams();
  const [video, setVideo] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get(`http://localhost:8000/api/videos/${id}/`)
      .then(response => {
        setVideo(response.data);
        setLoading(false);
      })
      .catch(error => {
        console.error('Ошибка загрузки видео:', error);
        setLoading(false);
      });
  }, [id]);

  if (loading) {
    return <div style={{ color: 'white', textAlign: 'center', marginTop: 50 }}>Загрузка...</div>;
  }

  if (!video) {
    return <div style={{ color: 'white', textAlign: 'center', marginTop: 50 }}>Видео не найдено</div>;
  }

  return (
    <div style={{ maxWidth: 1200, margin: '0 auto' }}>
      <video
        src={`http://localhost:8000/api/videos/${id}/stream/`}
        controls
        style={{ width: '100%', borderRadius: 12 }}
        autoPlay
      />
      <h1 style={{ color: 'white', marginTop: 20 }}>{video.title}</h1>
      <p style={{ color: '#aaa' }}>{video.description}</p>
      <div style={{ color: '#888', marginTop: 10 }}>
        {video.views || 0} просмотров • {video.uploaded_by_name || 'Аноним'}
      </div>
    </div>
  );
}

export default VideoPlayerPage;
